#!/usr/bin/env node
import fs from "node:fs/promises";
import path from "node:path";
import process from "node:process";
import sharp from "sharp";

const root = process.cwd();
const manifestPath = path.join(root, "scripts/mockup-extraction-manifest.json");
const manifest = JSON.parse(await fs.readFile(manifestPath, "utf8"));
const tolerance = Number(manifest.backgroundTolerance ?? 34);
const generatedRules = [
  "/* This file is generated by `npm run extract:mockups`.",
  "   It stores placement data measured from approved source mockups so the live page can reconstruct the composition without rendering full mockups. */",
  "",
];
const missingSources = [];
const extracted = [];

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function colorDistanceSq(a, b) {
  const dr = a[0] - b[0];
  const dg = a[1] - b[1];
  const db = a[2] - b[2];
  return dr * dr + dg * dg + db * db;
}

function median(values) {
  const sorted = [...values].sort((a, b) => a - b);
  return sorted[Math.floor(sorted.length / 2)] ?? 0;
}

function estimateBackground(buffer, width, height) {
  const samples = [];
  const sampleSize = Math.max(4, Math.floor(Math.min(width, height) * 0.045));
  const points = [
    [0, 0],
    [width - sampleSize, 0],
    [0, height - sampleSize],
    [width - sampleSize, height - sampleSize],
  ];

  for (const [startX, startY] of points) {
    for (let y = startY; y < startY + sampleSize; y += 2) {
      for (let x = startX; x < startX + sampleSize; x += 2) {
        const idx = (y * width + x) * 4;
        samples.push([buffer[idx], buffer[idx + 1], buffer[idx + 2]]);
      }
    }
  }

  return [
    median(samples.map((pixel) => pixel[0])),
    median(samples.map((pixel) => pixel[1])),
    median(samples.map((pixel) => pixel[2])),
  ];
}

function makeTransparentCrop({ buffer, width, height, background }) {
  const output = Buffer.from(buffer);
  const maxDistance = tolerance * tolerance;
  const visited = new Uint8Array(width * height);
  const queue = [];

  function push(x, y) {
    if (x < 0 || x >= width || y < 0 || y >= height) return;
    const pos = y * width + x;
    if (visited[pos]) return;
    const idx = pos * 4;
    if (colorDistanceSq([output[idx], output[idx + 1], output[idx + 2]], background) > maxDistance) return;
    visited[pos] = 1;
    queue.push([x, y]);
  }

  for (let x = 0; x < width; x++) {
    push(x, 0);
    push(x, height - 1);
  }
  for (let y = 0; y < height; y++) {
    push(0, y);
    push(width - 1, y);
  }

  for (let i = 0; i < queue.length; i++) {
    const [x, y] = queue[i];
    const idx = (y * width + x) * 4;
    output[idx + 3] = 0;
    push(x + 1, y);
    push(x - 1, y);
    push(x, y + 1);
    push(x, y - 1);
  }

  let minX = width;
  let minY = height;
  let maxX = -1;
  let maxY = -1;

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const alpha = output[(y * width + x) * 4 + 3];
      if (alpha > 10) {
        minX = Math.min(minX, x);
        minY = Math.min(minY, y);
        maxX = Math.max(maxX, x);
        maxY = Math.max(maxY, y);
      }
    }
  }

  if (maxX < minX || maxY < minY) {
    return { buffer: output, trim: { left: 0, top: 0, width, height } };
  }

  const safe = 8;
  minX = clamp(minX - safe, 0, width - 1);
  minY = clamp(minY - safe, 0, height - 1);
  maxX = clamp(maxX + safe, 0, width - 1);
  maxY = clamp(maxY + safe, 0, height - 1);

  return {
    buffer: output,
    trim: {
      left: minX,
      top: minY,
      width: maxX - minX + 1,
      height: maxY - minY + 1,
    },
  };
}

function cropToPixels(crop, width, height) {
  const [x, y, w, h] = crop;
  const left = Math.round(x * width);
  const top = Math.round(y * height);
  return {
    left: clamp(left, 0, width - 1),
    top: clamp(top, 0, height - 1),
    width: clamp(Math.round(w * width), 1, width - left),
    height: clamp(Math.round(h * height), 1, height - top),
  };
}

async function copyLayoutGuide(sourcePath, sourceName) {
  const targetPath = path.join(root, manifest.layoutGuideDir, sourceName);
  await fs.mkdir(path.dirname(targetPath), { recursive: true });
  await fs.copyFile(sourcePath, targetPath);
}

for (const section of manifest.sections) {
  const sourcePath = path.join(root, manifest.sourceDir, section.source);
  try {
    await fs.access(sourcePath);
  } catch {
    missingSources.push(sourcePath);
    continue;
  }

  await copyLayoutGuide(sourcePath, section.source);
  const sourceImage = sharp(sourcePath).ensureAlpha();
  const metadata = await sourceImage.metadata();
  const sourceWidth = metadata.width;
  const sourceHeight = metadata.height;
  if (!sourceWidth || !sourceHeight) {
    throw new Error(`Cannot read dimensions for ${sourcePath}`);
  }

  const raw = await sourceImage.raw().toBuffer();
  const background = estimateBackground(raw, sourceWidth, sourceHeight);

  for (const asset of section.assets) {
    const crop = cropToPixels(asset.crop, sourceWidth, sourceHeight);
    const cropBuffer = await sharp(raw, {
      raw: { width: sourceWidth, height: sourceHeight, channels: 4 },
    })
      .extract(crop)
      .raw()
      .toBuffer();

    const transparent = makeTransparentCrop({
      buffer: cropBuffer,
      width: crop.width,
      height: crop.height,
      background,
    });

    const outPath = path.join(root, asset.output);
    await fs.mkdir(path.dirname(outPath), { recursive: true });
    await sharp(transparent.buffer, {
      raw: { width: crop.width, height: crop.height, channels: 4 },
    })
      .extract(transparent.trim)
      .webp({ quality: 92, effort: 5 })
      .toFile(outPath);

    const left = ((crop.left + transparent.trim.left) / sourceWidth) * 100;
    const top = ((crop.top + transparent.trim.top) / sourceHeight) * 100;
    const width = (transparent.trim.width / sourceWidth) * 100;
    const height = (transparent.trim.height / sourceHeight) * 100;

    generatedRules.push(`${asset.selector} { left: ${left.toFixed(3)}%; top: ${top.toFixed(3)}%; width: ${width.toFixed(3)}%; height: ${height.toFixed(3)}%; right: auto; bottom: auto; }`);
    extracted.push(asset.output);
  }
}

await fs.mkdir(path.dirname(path.join(root, manifest.generatedCss)), { recursive: true });
await fs.writeFile(path.join(root, manifest.generatedCss), `${generatedRules.join("\n")}\n`, "utf8");

if (missingSources.length > 0) {
  console.warn("Missing source mockups; skipped extraction for:");
  for (const source of missingSources) console.warn(`- ${path.relative(root, source)}`);
}

console.log(`Extracted ${extracted.length} assets.`);
if (extracted.length > 0) {
  for (const output of extracted) console.log(`- ${output}`);
}
console.log(`Wrote ${manifest.generatedCss}`);
